  # offset too small to modify counter for checking
1:
  nop

# branch forward by 8
  bge x29, x27, 2f
  addi x17, x17, -2 # shouldn't happen
2:
  addi x17, x17, 4 # should happen

# branch forward by 16
  bge x29, x27, 3f
  addi x17, x17, -8 # shouldn't happen
  j 19f # shouldn't happen
  nop # use up 4 bytes
