  addi x17, x17, 64 # should happen

# branch forward by 4092
  .align 12 # align to 4096 bytes
  nop # use up 4 bytes
  bge x29, x27, 5f
  addi x17, x17, -128 # shouldn't happen
  j 19f # shouldn't happen
  .align 12 # align to 4096 bytes
